mapper.select:
SELECT COUNT(1)
FROM blog_column
WHERE id = #{id}

SELECT COUNT(1)
FROM blog_column_article
WHERE column_id = #{columnId}
AND article_id = #{articleId}

SELECT FROM blog_column c WHERE c.deleted_at IS NULL
AND (c.title LIKE CONCAT('%', #{keyword}, '%') OR c.summary LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY c.sort_order ASC, c.id DESC LIMIT #{offset}, #{limit}
